/* ===========================================================================
 * Search loading spinner
 *
 * render() must show a spinner in the results container while a SEARCH fetch is
 * in flight, so the user sees immediate feedback between clearing the old
 * results and the new table arriving. The spinner is inserted imperatively
 * (document.createElement) between `resultsEl.innerHTML = ''` and the `try`
 * block, guarded by `route.view === 'search'` — so browse renders never show
 * one. No explicit removal is needed: renderSearch clears innerHTML before
 * building the table, and the error handler sets textContent; both replace the
 * spinner. The race-token guard already prevents a superseded render's spinner
 * from clobbering a fresher render.
 * ========================================================================= */
describe('search loading spinner', () => {
  /**
   * Override the global fetch so the SEARCH request for `heldQuery` stays open
   * until `release()` is called; every other search query and all browse
   * requests resolve immediately with a recognizable result. Mirrors the
   * stubHeldBrowse pattern used by the render-race suite.
   */
  function stubHeldSearch(heldQuery: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: {
              query: heldQuery,
              path: '',
              results: [
                fileEntry({
                  name: 'result-for-' + heldQuery,
                  path: joinPathHelper('docs', 'result-for-' + heldQuery),
                }),
              ],
            } as SearchResult,
          }),
        );
    });

    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        if (query === heldQuery) {
          return held;
        }
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    return { release };
  }

  it('shows a spinner in the results container while a search fetch is in flight', async () => {
    const { release } = stubHeldSearch('slow');

    const { results } = setup();
    await flush(); // settle the initial browse render

    // Navigate to a search whose fetch is held. In happy-dom the hashchange
    // fires synchronously, so render() runs up to its first await (the held
    // fetch) before this line continues — the spinner must already be in the DOM.
    navigate(toSearchHash('slow', ''));

    const spinner = results.querySelector('.search-spinner');
    expect(spinner).not.toBeNull();
    // Built imperatively: an <i> glyph child with the spinning classes.
    const icon = spinner!.querySelector('i');
    expect(icon).not.toBeNull();
    expect(icon!.className).toBe('bi bi-arrow-repeat spinning');

    // Releasing the fetch lets the search render commit the results table,
    // which replaces the spinner (renderSearch clears innerHTML first).
    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-slow');
  });

  it('shows the spinner during the INITIAL render when the route is a search', async () => {
    const { release } = stubHeldSearch('initial');

    // Start the app directly on a search route. The initial render() runs
    // synchronously up to its first await, so the spinner is present before
    // any microtask flush.
    const { results } = setup({ hash: toSearchHash('initial', '') });

    expect(results.querySelector('.search-spinner')).not.toBeNull();

    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('does NOT show a spinner for browse routes', async () => {
    // Hold the browse fetch so the spinner — if it were wrongly added — would
    // be observable while the fetch is in flight.
    let releaseBrowse!: () => void;
    const heldBrowse = new Promise<Response>((resolve) => {
      releaseBrowse = () =>
        resolve(
          mockResponse({
            body: browseResult({
              path: 'somewhere',
              entries: [fileEntry({ name: 'a', path: 'somewhere/a', size: 1 })],
              fileCount: 1,
              totalSize: 1,
            }),
          }),
        );
    });
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        return heldBrowse;
      }
      return mockResponse({ status: 200, body: {} });
    });

    const { results } = setup({ hash: toBrowseHash('somewhere') });
    // Initial browse render is in flight (held): no spinner should appear.
    expect(results.querySelector('.search-spinner')).toBeNull();

    releaseBrowse();
    await flush();
    // After it commits, still no spinner — just the table.
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();

    // Also navigating browse → browse never introduces a spinner.
    fetchMock.mockImplementation(async () => mockResponse({ status: 200, body: {} }));
    // (reset not strictly needed; just assert the invariant again)
  });

  it('removes the spinner and shows an error message when the search fetch fails', async () => {
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        return mockResponse({ status: 500, text: 'search exploded' });
      }
      return mockResponse({ status: 200, body: {} });
    });

    const { results } = setup();
    await flush();

    navigate(toSearchHash('anything', ''));
    await flush();

    // The error handler sets textContent, replacing the spinner.
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeNull();
    expect((results.textContent ?? '').trim()).toContain('search exploded');
  });

  it('the spinner is a single element and is the only results child while pending', async () => {
    const { release } = stubHeldSearch('only');

    const { results } = setup();
    await flush();

    navigate(toSearchHash('only', ''));

    // While the search fetch is in flight, the results container should contain
    // exactly one child: the spinner div.
    const spinners = results.querySelectorAll('.search-spinner');
    expect(spinners).toHaveLength(1);
    expect(results.children).toHaveLength(1);
    expect(results.firstElementChild).toBe(spinners[0]);

    release();
    await flush();
  });
});
