/* ===========================================================================
 * Search loading spinner
 *
 * `render()` must show a spinner in the results container while a SEARCH fetch
 * is in flight, so the user sees immediate feedback after the old results are
 * cleared and before the new table arrives. The spinner is built imperatively
 * (document.createElement) and appended between `resultsEl.innerHTML = ''` and
 * the `try` block, guarded by `route.view === 'search'` — browse renders never
 * show one. No explicit removal is required: `renderSearch` clears innerHTML
 * before building its table, and the error handler sets textContent; both
 * replace the spinner. The existing race-token guard already prevents a
 * superseded render's spinner from clobbering a fresher render.
 *
 * The spinner DOM contract (per the spec):
 *   <div class="search-spinner">
 *     <i class="bi bi-arrow-repeat spinning"></i>
 *   </div>
 * ========================================================================= */
describe('search loading spinner', () => {
  /**
   * Override the global fetch so the SEARCH request for `heldQuery` stays open
   * until `release()` is called; every other search query resolves immediately
   * with a recognizable result, and browse requests resolve immediately too.
   * Mirrors the `stubHeldBrowse` pattern used by the render-race suite, letting
   * a test observe the in-flight spinner before the search render commits.
   */
  function stubHeldSearch(heldQuery: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: {
              query: heldQuery,
              path: '',
              results: [
                fileEntry({
                  name: 'result-for-' + heldQuery,
                  path: joinPathHelper('docs', 'result-for-' + heldQuery),
                }),
              ],
            } as SearchResult,
          }),
        );
    });

    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        if (query === heldQuery) {
          return held;
        }
        return mockResponse({
          body: {
            query,
            path: '',
            results: [
              fileEntry({
                name: 'result-for-' + query,
                path: joinPathHelper('docs', 'result-for-' + query),
              }),
            ],
          } as SearchResult,
        });
      }
      if (method === 'GET' && u.includes('/browse')) {
        const raw = u.split('path=')[1] ?? '';
        const path = decodeURIComponent(raw);
        const childName = 'child-of-' + (path || 'root');
        return mockResponse({
          body: browseResult({
            path,
            entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
            fileCount: 1,
            totalSize: 10,
          }),
        });
      }
      return mockResponse({ status: 200, body: {} });
    });

    return { release };
  }

  it('shows a spinner with the required structure while a search fetch is in flight', async () => {
    const { release } = stubHeldSearch('slow');

    const { results } = setup();
    await flush(); // settle the initial browse render

    // Navigate to a search whose fetch is held. In happy-dom assigning to
    // location.hash fires `hashchange` synchronously, so `render()` runs up to
    // its first await (the held fetch) before this line continues — the spinner
    // must already be in the DOM.
    navigate(toSearchHash('slow', ''));

    const spinner = results.querySelector('.search-spinner');
    expect(spinner).not.toBeNull();
    expect(spinner!.className).toBe('search-spinner');

    // Built imperatively: an <i> glyph child carrying the spinning classes.
    const icon = spinner!.querySelector('i');
    expect(icon).not.toBeNull();
    expect(icon!.className).toBe('bi bi-arrow-repeat spinning');

    // Releasing the fetch lets the search render commit its results table,
    // which replaces the spinner (renderSearch clears innerHTML first).
    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-slow');
  });

  it('the spinner is the only child of the results container while pending', async () => {
    const { release } = stubHeldSearch('only');

    const { results } = setup();
    await flush();

    navigate(toSearchHash('only', ''));

    // While the search fetch is in flight, the results container holds exactly
    // one child — the spinner div — and never more than one.
    const spinners = results.querySelectorAll('.search-spinner');
    expect(spinners).toHaveLength(1);
    expect(results.children).toHaveLength(1);
    expect(results.firstElementChild).toBe(spinners[0]);

    release();
    await flush();
  });

  it('shows the spinner during the INITIAL render when the starting route is a search', async () => {
    const { release } = stubHeldSearch('initial');

    // Start the app directly on a search route. `startApp` → `init` → `render()`
    // runs synchronously up to its first await, so the spinner is present before
    // any microtask flush.
    const { results } = setup({ hash: toSearchHash('initial', '') });

    expect(results.querySelector('.search-spinner')).not.toBeNull();

    release();
    await flush();

    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('does NOT show a spinner for browse routes', async () => {
    const { results } = setup({ hash: toBrowseHash('somewhere') });

    // The initial browse render is suspended at its first await: results are
    // cleared, but no spinner appears (spinner insertion is search-only).
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.children).toHaveLength(0);

    await flush();

    // After the browse render commits the table, there is still no spinner.
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeTruthy();

    // Navigating browse → browse also never introduces a spinner.
    navigate(toBrowseHash('elsewhere'));
    expect(results.querySelector('.search-spinner')).toBeNull();
    await flush();
  });

  it('removes the spinner and shows an error message when the search fetch fails', async () => {
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        return mockResponse({ status: 500, text: 'search exploded' });
      }
      return mockResponse({ status: 200, body: {} });
    });

    const { results } = setup();
    await flush();

    navigate(toSearchHash('anything', ''));
    await flush();

    // The error handler sets `textContent`, replacing the spinner with the
    // error message; no spinner and no table remain.
    expect(results.querySelector('.search-spinner')).toBeNull();
    expect(results.querySelector('table')).toBeNull();
    expect((results.textContent ?? '').trim()).toContain('search exploded');
  });
});

